from flask import jsonify, request
from flask_jwt_extended import jwt_required, get_jwt_identity

@app.route('/api/users/me', methods=['PUT'])
@jwt_required()
def update_user():
    current_user = get_jwt_identity()
    data = request.get_json()

    # Check if the user is allowed to modify these fields
    if not current_user['is_admin'] and 'email' in data:
        return jsonify({'error': 'You are not authorized to update your email.'}), 403
    if not current_user['is_admin'] and 'username' in data:
        return jsonify({'error': 'You are not authorized to update your username.'}), 403
    if not current_user['is_admin'] and 'account_type' in data:
        return jsonify({'error': 'You are not authorized to update your account type.'}), 403
    if not current_user['is_admin'] and 'credits' in data:
        return jsonify({'error': 'You are not authorized to update your credits.'}), 403
    if not current_user['is_admin'] and 'referral_code' in data:
        return jsonify({'error': 'You are not authorized to update your referral code.'}), 403
    if not current_user['is_admin'] and 'verified_status' in data:
        return jsonify({'error': 'You are not authorized to update your verified status.'}), 403

    # Update the user's profile with the new data
    for key, value in data.items():
        current_user[key] = value

    return jsonify({'message': 'User updated successfully.'})